module RefModule(
    input clk,
    input parallel_load,
    input serial_in,
    output serial_out,
    input [3:0] data_in
);reg [3:0] obf_register;

    always @(posedge clk) begin
        if (parallel_load) begin
            obf_register <= data_in;
        end else begin
            obf_register <= {obf_register[2:0], serial_in};
        end
    end

    assign serial_out = obf_register[0];

endmodule
